# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

import strawberry
from strawberry import Schema
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey, DateTime
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker
from typing import List
from datetime import datetime

engine = create_engine('sqlite:///graphql.db')
SessionLocal = sessionmaker(bind=engine)

Base = declarative_base()

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Integer)
    category_id = Column(ForeignKey('categories.id'))

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    product_id = Column(ForeignKey('products.id'))
    rating = Column(Integer)
    comment = Column(String)

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship('Product', backref='seller')

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship('Product', backref='category')

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    product_id = Column(ForeignKey('products.id'))
    url = Column(String)

Base.metadata.create_all(engine)

@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: int
    category: 'Category'
    reviews: List['Review']
    seller: 'Seller'
    images: List['Image']

@strawberry.input
class CreateProductInput:
    name: str
    description: str
    price: int

@strawberry.input
class UpdateProductInput:
    id: int
    name: str
    description: str
    price: int

@strawberry.type
class Query:
    @strawberry.field
    def products(self, info) -> List[ProductType]:
        session = SessionLocal()
        return [ProductType(
            id=p.id,
            name=p.name,
            description=p.description,
            price=p.price,
            category=Category(id=p.category_id),
            reviews=[Review(id=r.id, product_id=r.product_id, rating=r.rating, comment=r.comment) for r in session.query(Review).filter_by(product_id=p.id)],
            seller=Seller(id=s.id, name=s.name) if p.seller else None,
            images=[Image(id=i.id, url=i.url) for i in session.query(Image).filter_by(product_id=p.id)]
        ) for p in session.query(Product)]

    @strawberry.field
    def product(self, info, id: int):
        session = SessionLocal()
        return ProductType(
            id=session.query(Product).get(id).id,
            name=session.query(Product).get(id).name,
            description=session.query(Product).get(id).description,
            price=session.query(Product).get(id).price,
            category=Category(id=session.query(Product).get(id).category_id),
            reviews=[Review(id=r.id, product_id=r.product_id, rating=r.rating, comment=r.comment) for r in session.query(Review).filter_by(product_id=id)],
            seller=Seller(id=s.id, name=s.name) if session.query(Product).get(id).seller else None,
            images=[Image(id=i.id, url=i.url) for i in session.query(Image).filter_by(product_id=id)]
        )

@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_product(self, info, input: CreateProductInput):
        session = SessionLocal()
        product = Product(
            name=input.name,
            description=input.description,
            price=input.price,
            category_id=1  # replace with actual category id
        )
        session.add(product)
        session.commit()

    @strawberry.mutation
    def update_product(self, info, input: UpdateProductInput):
        session = SessionLocal()
        product = session.query(Product).get(input.id)
        if product:
            product.name = input.name
            product.description = input.description
            product.price = input.price
            session.commit()

schema = Schema(Query, Mutation)

